          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "Why does a voltage drop occur in the supply cables before the electricity even reaches the intended appliance?",
      "deeperAnswerGuidance": [
        "Supply cables have their own resistance",
        "Current must flow through the cable resistance",
        "Pressure is lost overcoming the cable's opposition",
        "Voltage drop happens in any conductor with resistance"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP4"
      ],
      "hint": "Think about whether a copper wire has zero resistance or just very low resistance."
    },
    {
      "title": "Linking Resistivity to Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "If a material with a higher resistivity is used for a cable, what happens to the cable's total resistance?",
          "answerGuidance": [
            "Increases",
            "Higher resistance"
          ],
          "hint": "Higher resistivity means the material is more opposing.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the effect on voltage drop if the resistance of a circuit is increased?",
          "answerGuidance": [
            "Increases",
            "Larger voltage drop"
          ],
          "hint": "More opposition leads to more pressure loss.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What is the primary practical reason electricians select copper to minimize voltage drop?",
          "answerGuidance": [
            "Low resistivity"
          ],
          "hint": "This material property ensures the least amount of resistance for a given size.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "How does the resistivity of a chosen cable material ultimately affect the operation of an electrical motor at the end of a long run?",
      "deeperAnswerGuidance": [
        "High resistivity increases cable resistance",
        "Increased resistance causes a larger voltage drop",
        "Less electrical pressure reaches the motor",
        "The motor may fail to operate correctly"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3",
        "TP4"
      ],
      "hint": "Connect the material's inherent property to the final 'pressure' available at the equipment."
    }
  ]
}

